## Problem1(A.9.5.51)
## Author()
## Institution()
## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PCCmacros.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
Context("Numeric");
Context()->noreduce('(-x)-y','(-x)+y');
$var = RandomVariableName(type=>'variable');
Context()->variables->are($var=>'Real');
$b = non_zero_random(-10,10,1);
do {$c = non_zero_random(-10,10,1);} until ($b!=$c);
$bPlusC = $b+$c;
$bc = $b*$c;
$binomial1 = Compute("$var+$b")->reduce;
$binomial2 = Compute("$var+$c")->reduce;
$s1 = Compute("$var**2+$b*$var")->reduce;
$s2 = Compute("$var**2+$bPlusC*$var+$bc")->reduce;
$problem = Compute("$var*($var+$b)*($var+$c)")->reduce;
$ans = Compute("$var**3+$bPlusC*$var**2+$bc*$var")->reduce;

############################################################
# Body
############################################################

BEGIN_PGML
Multiply the binomial with the binomial, writing the result as a single simplified polynomial.

[`[$problem]`]

[_]{$ans}{16}

END_PGML

############################################################
# Solution
############################################################

BEGIN_PGML_SOLUTION
We could first distribute [`[$var]`] into [`[$binomial1]`] to get [`[$s1]\text{,}`] and then multiply [`[$s1]`] and [`[$binomial2]\text{:}`]

[```\newcommand{\amp}{&}
\begin{aligned}
[$problem]\amp=([$s1])([$binomial2])\\
\amp=[$ans]
\end{aligned}
```]

We could also first multiply [`[$binomial1]`] and [`[$binomial2]`] to get [`[$s2]\text{,}`] and then distribute [`[$var]`] into [`[$s2]\text{:}`]

[```\newcommand{\amp}{&}
\begin{aligned}
[$problem]\amp=[$var]([$s2])\\
\amp=[$ans]
\end{aligned}
```]

END_PGML_SOLUTION

############################################################
# End Problem
############################################################

ENDDOCUMENT();
